inline constexpr std::uint32_t highlight_row_color = 0x046a9e;


inline ImVec4 to_color(std::uint32_t rgb) {
    return ImVec4(
        (rgb >> 16 & 0xff) / 255.f,
        (rgb >>  8 & 0xff) / 255.f,
        (rgb & 0xff) / 255.f,
        1.0f
    );
}

inline ImVec4 get_gradient_interp(const double t) {
    const double interp = (1 - t) * (detail::heat_cmap.size() - 1);
    return to_color(detail::heat_cmap[static_cast<std::uint32_t>(interp)]);
}
